var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"……다들 그만.","JPN":"……そこまで。","ENG":"...That's enough, everyone.","TWN":"……好了。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"이 정도면 충분할 것 같구나, 로즈.","JPN":"このくらいで十分よ、ローズ。","ENG":"That should suffice, Rose.","TWN":"可以了，玫瑰。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"알겠습니다, 마스터. 전 인원 교전 중지.","JPN":"わかりました、マスター。全員、交戦中止。","ENG":"Understood, Master. All units, cease engagement.","TWN":"是的，主人。全員停止交戰。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"}}}},{"id":"L13_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"블랙 로즈 1개 분대, 별도 지시가 있을 때까지 대기합니다.","JPN":"ブラックローズ第1分隊、別途指示があるまで待機します。","ENG":"Black Rose, Squad One, remain on standby until further orders.","TWN":"黑玫瑰1個分隊，待命中。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_PRIDE"},"R":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아… 하아… 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff...* *Huff...* *Huff...!*","TWN":"呼……呼……呼！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 겨우 이걸로 끝이야? 어디 더 붙어 보자고……!","JPN":"くそ、これで終わりか？　こっちはまだまだ行けるけどな……！","ENG":"Damn it, that's all you got? Come on, bring it on...!","TWN":"可惡，就這樣結束了嗎？再來試試吧！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"숨부터 고르고 말해요, 라이카. 호흡이 엉망이잖아요.","JPN":"息を整えてから言いなさいよ、ライカ。呼吸が乱れているわ。","ENG":"Catch your breath before yelling, Laika. You're all over the place.","TWN":"先調整呼吸再說話，萊卡。你的呼吸太亂了。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러게 내가 뭐랬어요. 슬슬 다음 시즌 리그 준비하면서 몸 만들어야 한다고 했죠?","JPN":"だから言ったじゃない。そろそろ来シーズンのリーグに備えて体を鍛えないとダメだって。","ENG":"Told you, didn't I? You should've been training for next season's League.","TWN":"我就說吧。該開始準備下個賽季的聯賽，鍛煉身體了吧？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"후우우……! 그래, 너 잘났다, 꼬맹아!","JPN":"ふうう……！　はいはい、その通りでございます、おこちゃま！","ENG":"Phewww...! Yeah, yeah, you're so smart, kid!","TWN":"呼呼……對，你最棒了，小鬼！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"근데 내 원래 계획에 다음 시즌 같은 건 없었어. 상금이나 펑펑 쓰면서 놀 생각이었거든.","JPN":"だけど、私の本来の計画には来シーズンなんてなかったんだ。賞金をガンガン使って遊ぶつもりだったから。","ENG":"But I never planned on a next season. I was gonna blow the prize money and take it easy.","TWN":"不過我原本的計畫裡沒有下個賽季。我打算拿獎金去好好享受一下。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭐라고요?","JPN":"なんですって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"블랙 로즈 분대의 공격을 버텨내다니…….","JPN":"ブラックローズ分隊の攻撃に耐えるなんて……","ENG":"To think you held out against the Black Rose Squad's assault...","TWN":"居然能撐過黑玫瑰分隊的攻擊……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"강아지풀 주제에 제법 분발했구나.","JPN":"エノコログサのくせに、やるじゃない。","ENG":"Not bad, Bristlegrass.","TWN":"作為狗尾草，表現得還不錯嘛。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"뭐, 예상했던 것보다 최악은 아니었어. 그렇다고 아주 좋지도 않았지만 말이지.","JPN":"まあ、予想していたよりは悪くなかったわ。かといって手放しで褒められるほどでもなかったけど。","ENG":"Well, it wasn't the worst outcome. But let's not pretend it was great either.","TWN":"嗯，比預想的情況要好一些。雖然不是特別好，但至少沒有那麼糟糕。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 그 어정쩡한 칭찬은?","JPN":"なんだよ、その中途半端な褒め方？","ENG":"What kind of half-baked compliment is that?","TWN":"什麼嘛？這種不痛不癢的誇獎？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나보고 어느 장단에 맞추라는 거야, 할망구?","JPN":"どう反応しろって言うんだ、ババァ。","ENG":"How am I supposed to react to that, hag?","TWN":"你讓我怎麼配合你，瘋婆子？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"일단, 임시방편으로 나이프를 섞은 격투술을 선택한 건 썩 나쁘지 않은 판단이었단다.","JPN":"まず、臨機応変にナイフを使った格闘術を選んだ点はなかなか悪くない判断だったわ。","ENG":"Choosing knife-based CQC as a stopgap wasn't a bad call.","TWN":"首先，選擇混合使用匕首的格鬥術作為權宜之計，並不是一個糟糕的判斷。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하지만 찌르기가 너무 얕구나. 동작 하나하나가 너무 크고.","JPN":"でも、突きが浅い。ひとつひとつの動作が大きすぎる。","ENG":"But your stabs are too shallow. Every movement's too big.","TWN":"不過刺得太淺了。每個動作幅度都太大了。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"맨션 메이드라는 타이틀이 아깝네. 적어도 나한테 그렇게 배우지는 않았을 텐데 말이지?","JPN":"マンションのメイドというタイトルが泣くわね。少なくとも私はそう教えなかったはずよ。","ENG":"Calling yourself a Mansion maid is a disgrace. I didn't raise you to fight like that, did I?","TWN":"真是浪費了曼森女僕這個稱號。至少我沒教過你這樣做吧？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시끄러워, 할망구! 누가 메이드라고……!","JPN":"うるさい、ババァ！　誰がメイドだ……！","ENG":"Shut up, hag! I'm not a maid...!","TWN":"吵死了，瘋婆子！誰說我是女僕！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 건틀렛에서 사람을 죽이면 실격 처리거든?","JPN":"それに、ガントレットでは人を殺すと失格なんだよ。","ENG":"And in the Gauntlet, killing someone gets you disqualified!","TWN":"而且在聖鎧中殺人是會被取消資格的喔？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"훈련이잖아. 급소는 피하는 게 상식이지!","JPN":"訓練だろ。急所を避けるのは常識だ！","ENG":"Plus, this is training. It's common sense to avoid vital points!","TWN":"這是訓練啊。避開要害是常識吧！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래? 그것 참 편리한 변명이로구나?","JPN":"そう？　便利な言い訳だこと。","ENG":"Oh? How convenient.","TWN":"是嗎？這個藉口可真是方便好用啊？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럼, 나중에 침식체를 상대로도 그렇게 말해보렴.","JPN":"だったら、後で侵食体が相手でもそう言ってみなさい。","ENG":"Try saying that when you're up against a C.O.","TWN":"那麼，之後你也可以對侵蝕體這麼說試試。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};